/**
 * SMS notification adapter.
 *
 * Delivers notifications via SMS with phone number validation and
 * message formatting. Uses a pluggable transport for actual delivery,
 * enabling real SMS providers (Twilio, etc.) in production and
 * in-memory capture in tests.
 *
 * NOTE: The user preferences model (src/models/user-preferences.ts) was
 * designed assuming email-only notifications. It needs to be updated to
 * support per-channel preferences (SMS enabled/disabled, SMS-specific
 * settings). See the warning posted to Twining for details.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * A formatted SMS message ready for transport.
 */
export interface SmsMessage {
  to: string;
  from: string;
  body: string;
}

/**
 * Transport interface for sending SMS messages.
 * Implement this for Twilio, AWS SNS, Vonage, etc.
 */
export interface SmsTransport {
  send(message: SmsMessage): Promise<{ success: boolean; messageId?: string; error?: string }>;
}

/**
 * Configuration for the SmsAdapter.
 */
export interface SmsAdapterConfig {
  /** Sender phone number or short code */
  fromNumber: string;
  /** Optional transport — defaults to in-memory capture transport */
  transport?: SmsTransport;
}

/**
 * Validates that a recipient string looks like a valid phone number.
 * Accepts E.164 format (+1234567890) and common variations.
 */
function isValidPhoneNumber(recipient: string): boolean {
  return /^\+?[1-9]\d{6,14}$/.test(recipient);
}

/**
 * Normalizes a phone number by stripping non-digit characters (except leading +).
 */
function normalizePhoneNumber(phone: string): string {
  const stripped = phone.replace(/[\s\-().]/g, '');
  return stripped;
}

/**
 * Default in-memory transport that captures sent messages for inspection.
 */
export class InMemorySmsTransport implements SmsTransport {
  private sent: SmsMessage[] = [];

  async send(message: SmsMessage): Promise<{ success: boolean; messageId?: string; error?: string }> {
    this.sent.push(message);
    return { success: true, messageId: `sms-${this.sent.length}` };
  }

  getSentMessages(): SmsMessage[] {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
  }
}

/**
 * Maximum length for a single SMS segment. Messages longer than this
 * are truncated with an ellipsis.
 */
const SMS_MAX_LENGTH = 160;

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private fromNumber: string;
  private transport: SmsTransport;
  private sentMessages: Array<{ payload: NotificationPayload; message: SmsMessage; sentAt: Date }> = [];

  constructor(config: SmsAdapterConfig) {
    this.fromNumber = config.fromNumber;
    this.transport = config.transport ?? new InMemorySmsTransport();
  }

  /**
   * Resolve and validate the recipient phone number from the payload.
   * Returns the normalized phone number or null if invalid.
   */
  resolveRecipient(payload: NotificationPayload): string | null {
    const normalized = normalizePhoneNumber(payload.recipient.trim());
    if (!isValidPhoneNumber(normalized)) {
      this.logger.warn(`Invalid SMS recipient: ${payload.recipient}`);
      return null;
    }
    return normalized;
  }

  /**
   * Format the notification payload as an SMS message body.
   * Truncates to SMS_MAX_LENGTH if necessary.
   */
  formatMessage(payload: NotificationPayload): string {
    const text = `${payload.subject}: ${payload.body}`;
    if (text.length <= SMS_MAX_LENGTH) {
      return text;
    }
    return text.substring(0, SMS_MAX_LENGTH - 3) + '...';
  }

  /**
   * Send a notification via SMS.
   *
   * 1. Resolves and validates the recipient phone number
   * 2. Formats the notification as an SMS message
   * 3. Delivers via the configured transport
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const resolved = this.resolveRecipient(payload);
    if (!resolved) {
      return {
        success: false,
        channel: 'sms',
        error: `Invalid recipient phone number: ${payload.recipient}`,
      };
    }

    const body = this.formatMessage(payload);
    const message: SmsMessage = {
      to: resolved,
      from: this.fromNumber,
      body,
    };

    try {
      const result = await this.transport.send(message);

      if (result.success) {
        this.sentMessages.push({ payload, message, sentAt: new Date() });
        this.logger.info(`SMS sent to ${resolved}: ${body.substring(0, 50)}`);
        return {
          success: true,
          channel: 'sms',
          deliveredAt: new Date(),
        };
      }

      this.logger.error(`SMS delivery failed for ${resolved}: ${result.error}`);
      return {
        success: false,
        channel: 'sms',
        error: result.error ?? 'SMS delivery failed',
      };
    } catch (err) {
      const errMessage = err instanceof Error ? err.message : String(err);
      this.logger.error(`SMS transport error for ${resolved}: ${errMessage}`);
      return {
        success: false,
        channel: 'sms',
        error: `Transport error: ${errMessage}`,
      };
    }
  }

  /**
   * Get all successfully sent messages. Useful for testing.
   */
  getSentMessages(): Array<{ payload: NotificationPayload; message: SmsMessage; sentAt: Date }> {
    return [...this.sentMessages];
  }

  /**
   * Clear sent message history. Useful for testing.
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  SmsAdapter,
  InMemorySmsTransport,
} from '../../src/adapters/sms.adapter.js';
import type {
  SmsTransport,
  SmsMessage,
} from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: '+15551234567',
    subject: 'Order Update',
    body: 'Your order has shipped.',
    channel: 'sms',
    priority: 'normal',
    ...overrides,
  };
}

const FROM_NUMBER = '+15559990000';

describe('SmsAdapter', () => {
  let transport: InMemorySmsTransport;
  let adapter: SmsAdapter;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
    adapter = new SmsAdapter({
      fromNumber: FROM_NUMBER,
      transport,
    });
  });

  describe('resolveRecipient', () => {
    it('should accept a valid E.164 phone number', () => {
      const payload = makePayload({ recipient: '+15551234567' });
      expect(adapter.resolveRecipient(payload)).toBe('+15551234567');
    });

    it('should accept a number without leading +', () => {
      const payload = makePayload({ recipient: '15551234567' });
      expect(adapter.resolveRecipient(payload)).toBe('15551234567');
    });

    it('should strip whitespace and formatting characters', () => {
      const payload = makePayload({ recipient: '+1 (555) 123-4567' });
      expect(adapter.resolveRecipient(payload)).toBe('+15551234567');
    });

    it('should reject an invalid phone number', () => {
      const payload = makePayload({ recipient: 'not-a-number' });
      expect(adapter.resolveRecipient(payload)).toBeNull();
    });

    it('should reject an empty string', () => {
      const payload = makePayload({ recipient: '' });
      expect(adapter.resolveRecipient(payload)).toBeNull();
    });

    it('should reject a number that is too short', () => {
      const payload = makePayload({ recipient: '+123' });
      expect(adapter.resolveRecipient(payload)).toBeNull();
    });
  });

  describe('formatMessage', () => {
    it('should combine subject and body', () => {
      const payload = makePayload();
      const msg = adapter.formatMessage(payload);
      expect(msg).toBe('Order Update: Your order has shipped.');
    });

    it('should truncate long messages to 160 characters', () => {
      const payload = makePayload({
        subject: 'Important',
        body: 'A'.repeat(200),
      });
      const msg = adapter.formatMessage(payload);
      expect(msg.length).toBe(160);
      expect(msg.endsWith('...')).toBe(true);
    });

    it('should not truncate messages at exactly 160 characters', () => {
      const payload = makePayload({
        subject: 'Hi',
        body: 'A'.repeat(156), // "Hi: " + 156 = 160
      });
      const msg = adapter.formatMessage(payload);
      expect(msg.length).toBe(160);
      expect(msg.endsWith('...')).toBe(false);
    });
  });

  describe('send', () => {
    it('should send a valid SMS successfully', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('sms');
      expect(result.deliveredAt).toBeInstanceOf(Date);

      const sent = transport.getSentMessages();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('+15551234567');
      expect(sent[0]?.from).toBe(FROM_NUMBER);
    });

    it('should fail for an invalid recipient', async () => {
      const payload = makePayload({ recipient: 'bad-number' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid recipient phone number');
      expect(transport.getSentMessages()).toHaveLength(0);
    });

    it('should handle transport failure', async () => {
      const failTransport: SmsTransport = {
        async send() {
          return { success: false, error: 'Carrier rejected message' };
        },
      };
      const failAdapter = new SmsAdapter({
        fromNumber: FROM_NUMBER,
        transport: failTransport,
      });

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Carrier rejected message');
    });

    it('should handle transport exception', async () => {
      const throwTransport: SmsTransport = {
        async send() {
          throw new Error('Network timeout');
        },
      };
      const throwAdapter = new SmsAdapter({
        fromNumber: FROM_NUMBER,
        transport: throwTransport,
      });

      const result = await throwAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Transport error: Network timeout');
    });

    it('should record sent messages for inspection', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ recipient: '+15559876543', subject: 'Second' }));

      const sent = adapter.getSentMessages();
      expect(sent).toHaveLength(2);
      expect(sent[0]?.payload.recipient).toBe('+15551234567');
      expect(sent[1]?.payload.recipient).toBe('+15559876543');
      expect(sent[1]?.message.body).toContain('Second');
    });

    it('should clear sent messages', async () => {
      await adapter.send(makePayload());
      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });
  });

  describe('defaults', () => {
    it('should use in-memory transport by default', async () => {
      const defaultAdapter = new SmsAdapter({ fromNumber: FROM_NUMBER });
      const result = await defaultAdapter.send(makePayload());

      expect(result.success).toBe(true);
      const sent = defaultAdapter.getSentMessages();
      expect(sent).toHaveLength(1);
    });
  });
});

describe('InMemorySmsTransport', () => {
  it('should capture and clear sent messages', async () => {
    const transport = new InMemorySmsTransport();
    const message: SmsMessage = {
      to: '+15551234567',
      from: '+15559990000',
      body: 'Hello',
    };

    await transport.send(message);
    expect(transport.getSentMessages()).toHaveLength(1);
    expect(transport.getSentMessages()[0]?.to).toBe('+15551234567');

    transport.clear();
    expect(transport.getSentMessages()).toHaveLength(0);
  });

  it('should return incrementing message IDs', async () => {
    const transport = new InMemorySmsTransport();
    const message: SmsMessage = { to: '+1555', from: '+1999', body: 'hi' };

    const r1 = await transport.send(message);
    const r2 = await transport.send(message);

    expect(r1.messageId).toBe('sms-1');
    expect(r2.messageId).toBe('sms-2');
  });
});

